// **************************************************************************************************************
// Title      : Application of Analytic Hierarchy Process for Mapping Flood Vulnerability in Odisha using Google Earth Engine
// Authors    : Pulakesh Pradhan, Rakesh Bajpai, Sribas Patra
// Contact    : pulakesh.mid@gmail.com
// DOI        : https://doi.org/10.1016/B978-0-443-27372-8.00025-8
// Citation   : Pradhan, P., Bajpai, R., & Patra, S. (2025). Application of analytic hierarchy process for mapping flood 
//              vulnerability in Odisha using Google Earth Engine. In *Elsevier eBooks* (pp. 399â€“420). 
//              https://doi.org/10.1016/B978-0-443-27372-8.00025-8
//
// Print DOI link
print('https://doi.org/10.1016/B978-0-443-27372-8.00025-8');
// **************************************************************************************************************

// ==========================
// Begin Code Implementation
// ==========================
// Set start and end year
var startyear = 2021;
var endyear = 2022;
// Make a date object
var startDate = ee.Date.fromYMD(startyear, 1, 1);
var endDate = ee.Date.fromYMD(endyear + 1, 1, 1);

// Make a list with years
var years = ee.List.sequence(startyear, endyear);

//Function to normalize
function normalize(image, minValue, maxValue) {
  return image.subtract(minValue).divide(maxValue - minValue);
}

// Define the region of interest (Odisha)
var geometry = ee.FeatureCollection('FAO/GAUL/2015/level1').filter(ee.Filter.eq('ADM1_NAME', 'Orissa'));

Map.centerObject(geometry)

// Set Default Viewpoint
var defaultCenterPoint = [83.95282597902448, 20.79701546664889];
var defaultZoom = 8;

// Elevation Data (DEM)
var dem = ee.Image('USGS/SRTMGL1_003').clip(geometry);
var demMinMax = dem.reduceRegion({reducer: ee.Reducer.minMax(), geometry: geometry, scale: 30, bestEffort: true});
print('DEM Min and Max:', demMinMax);

// Slope Calculation
var slope = ee.Terrain.slope(dem);
var slopeMinMax = slope.reduceRegion({reducer: ee.Reducer.minMax(), geometry: geometry, scale: 30, bestEffort: true});
print('Slope Min and Max:', slopeMinMax);

// Soil Properties
var clayISRIC = ee.Image("projects/soilgrids-isric/clay_mean").select('clay_0-5cm_mean').clip(geometry);
var clayMinMax = clayISRIC.reduceRegion({reducer: ee.Reducer.minMax(), geometry: geometry, scale: 250, bestEffort: true});
print('Clay Min and Max:', clayMinMax);

var sandISRIC = ee.Image("projects/soilgrids-isric/sand_mean").select('sand_0-5cm_mean').clip(geometry);
var sandMinMax = sandISRIC.reduceRegion({reducer: ee.Reducer.minMax(), geometry: geometry, scale: 250, bestEffort: true});
print('Sand Min and Max:', sandMinMax);

var siltISRIC = ee.Image("projects/soilgrids-isric/silt_mean").select('silt_0-5cm_mean').clip(geometry);
var siltMinMax = siltISRIC.reduceRegion({reducer: ee.Reducer.minMax(), geometry: geometry, scale: 250, bestEffort: true});
print('Silt Min and Max:', siltMinMax);

// Water Body Data
var dataset = ee.ImageCollection('GLCF/GLS_WATER').filterBounds(geometry).max();
var water = dataset.clip(geometry);
var waterMinMax = water.reduceRegion({reducer: ee.Reducer.minMax(), geometry: geometry, scale: 30, bestEffort: true});
print('Water Min and Max:', waterMinMax);

// Distance from Water
var distWater = water.select('water').eq(2)
  .distance({kernel: ee.Kernel.euclidean(100), skipMasked: false})
  .clip(geometry)
  .rename('distance');
var distWaterMinMax = distWater.reduceRegion({reducer: ee.Reducer.minMax(), geometry: geometry, scale: 30, bestEffort: true});
print('Distance from Water Min and Max:', distWaterMinMax);

// Flow Accumulation
var flowaccumImage = ee.Image('WWF/HydroSHEDS/15ACC');

// Topographic Wetness Index (TWI)
var twiImage = ((flowaccumImage.add(1)).multiply(ee.Image.pixelArea())
             .divide((slope.multiply(0.0174528)).tan()).add(0.001).log()).rename('TWI');

// NDVI
var ndviCollection = ee.ImageCollection('MODIS/006/MOD13A1')
  .filter(ee.Filter.date(startDate, endDate))
  .select('NDVI').mean().clip(geometry);

// Rainfall Data
var chirps = ee.ImageCollection("UCSB-CHG/CHIRPS/PENTAD");
var annualPrecip = ee.ImageCollection.fromImages(
  years.map(function (year) {
    var annual = chirps.filter(ee.Filter.calendarRange(year, year, 'year')).sum();
    return annual.set('year', year).set('system:time_start', ee.Date.fromYMD(year, 1, 1));
  })
);
var annualMean = annualPrecip.mean().clip (geometry);

// Normalizing the Data
var normDEM = normalize(dem, (-68), 1664);
var normSlope = normalize(slope, (0), 77.99649810791016);
var normClay = normalize(clayISRIC, (189), 468);
var normSand = normalize(sandISRIC, (99), 684);
var normSilt = normalize(siltISRIC, (107), 578);
var normWaterDis = normalize(distWater, (0), 141.4213562373095);
var normTWI = normalize(twiImage, (-6.907755278982137), 24.282822036966103);
var normNDVI = normalize(ndviCollection, (-1978), 9282);
var normRain = normalize(annualMean, (1102.677119962871), 2178.0353754013777);

// Assigning Weightages and Classifying Layers
var demClassified = normDEM.where(normDEM.lt(0.2), normDEM.multiply(3.50))
    .where(normDEM.gte(0.2).and(normDEM.lt(0.4)), normDEM.multiply(2.10))
    .where(normDEM.gte(0.4).and(normDEM.lt(0.6)), normDEM.multiply(0.70))
    .where(normDEM.gte(0.6), normDEM.multiply(0.70));

var slopeClassified = normSlope.where(normSlope.lt(0.2), normSlope.multiply(11.50))
    .where(normSlope.gte(0.2).and(normSlope.lt(0.4)), normSlope.multiply(6.90))
    .where(normSlope.gte(0.4).and(normSlope.lt(0.6)), normSlope.multiply(3.45))
    .where(normSlope.gte(0.6), normSlope.multiply(1.15));

var clayClassified = normClay.where(normClay.lt(0.2), normClay.multiply(1))
    .where(normClay.gte(0.2).and(normClay.lt(0.4)), normClay.multiply(0.60))
    .where(normClay.gte(0.4).and(normClay.lt(0.6)), normClay.multiply(0.40))
    .where(normClay.gte(0.6), normClay.multiply(0.20));

var sandClassified = normSand.where(normSand.lt(0.2), normSand.multiply(5))
    .where(normSand.gte(0.2).and(normSand.lt(0.4)), normSand.multiply(4))
    .where(normSand.gte(0.4).and(normSand.lt(0.6)), normSand.multiply(3))
    .where(normSand.gte(0.6), normSand.multiply(2));

var siltClassified = normSilt.where(normSilt.lt(0.2), normSilt.multiply(5))
    .where(normSilt.gte(0.2).and(normSilt.lt(0.4)), normSilt.multiply(4))
    .where(normSilt.gte(0.4).and(normSilt.lt(0.6)), normSilt.multiply(3))
    .where(normSilt.gte(0.6), normSilt.multiply(2));

var waterDisClassified = normWaterDis.where(normWaterDis.lt(0.2), normWaterDis.multiply(1.80))
    .where(normWaterDis.gte(0.2).and(normWaterDis.lt(0.4)), normWaterDis.multiply(0.6))
    .where(normWaterDis.gte(0.4).and(normWaterDis.lt(0.6)), normWaterDis.multiply(0.45))
    .where(normWaterDis.gte(0.6), normWaterDis.multiply(0.15));

var twiClassified = normTWI.where(normTWI.lt(0.2), normTWI.multiply(6.40))
    .where(normTWI.gte(0.2).and(normTWI.lt(0.4)), normTWI.multiply(4.80))
    .where(normTWI.gte(0.4).and(normTWI.lt(0.6)), normTWI.multiply(3.20))
    .where(normTWI.gte(0.6), normTWI.multiply(1.60));

var ndviClassified = normNDVI.where(normNDVI.lt(0.2), normNDVI.multiply(2.50))
    .where(normNDVI.gte(0.2).and(normNDVI.lt(0.4)), normNDVI.multiply(1.50))
    .where(normNDVI.gte(0.4).and(normNDVI.lt(0.6)), normNDVI.multiply(0.75))
    .where(normNDVI.gte(0.6), normNDVI.multiply(0.25));

var rainClassified = normRain.where(normRain.lt(0.2), normRain.multiply(3.30))
    .where(normRain.gte(0.2).and(normRain.lt(0.4)), normRain.multiply(6.60))
    .where(normRain.gte(0.4).and(normRain.lt(0.6)), normRain.multiply(9.90))
    .where(normRain.gte(0.6), normRain.multiply(13.20));

// Land Use Land Cover (LULC) classification
var lulcClasses = ee.ImageCollection('GOOGLE/DYNAMICWORLD/V1').filter(ee.Filter.date(startDate, endDate)).select('label').mosaic().clip(geometry);

//LULC total waight = 7.88
var lulcClassesWeightage = lulcClasses
  .where(lulcClasses.eq(0), lulcClasses.multiply(1.1))
  .where(lulcClasses.eq(1), lulcClasses.multiply(1.65))
  .where(lulcClasses.eq(2), lulcClasses.multiply(1.65))
  .where(lulcClasses.eq(3), lulcClasses.multiply(0.55))
  .where(lulcClasses.eq(4), lulcClasses.multiply(1.65))
  .where(lulcClasses.eq(5), lulcClasses.multiply(2.2))
  .where(lulcClasses.eq(6), lulcClasses.multiply(1.1))
  .where(lulcClasses.eq(7), lulcClasses.multiply(0.55))
  .where(lulcClasses.eq(8), lulcClasses.multiply(0.55));

var lulcVisWeightage = {
  min: 0,
  max: 8,
  palette: ['#419BDF', '#397D49', '#88B053', '#7A87C6',
    '#E49635', '#DFC35A', '#C4281B', '#A59B8F', '#B39FE1']
};
Map.addLayer(lulcClasses, lulcVisWeightage, "LULC");

// Combine Layers into a Flood Susceptibility Map
var allLayers = demClassified
    .add(slopeClassified)
    .add(clayClassified)
    .add(sandClassified)
    .add(siltClassified)
    .add(waterDisClassified)
    .add(twiClassified)
    .add(ndviClassified)
    .add(rainClassified)
    .add(lulcClassesWeightage)
    .rename('ahp');

var normalizedAHPCalculation = normalize(allLayers, (0.4629975633999295), 27.592958559295713);

var ahpVis = {
  min:0,
  max:1,
  palette: ['#d53e4f','#f46d43','#fdae61','#fee08b','#ffffbf','#e6f598','#abdda4','#66c2a5','#3288bd'].reverse()
};
Map.addLayer(normalizedAHPCalculation.clip(geometry), ahpVis, 'Flood Susceptibility (AHP)');

Export.image.toDrive({
  image: normalizedAHPCalculation,
  description:"AHP_Resluts",
  folder: "GEE",
  region: geometry,
  scale: 5000,
  crs: "EPSG:32645",
  maxPixels: 1e16,
  fileFormat: "GEO_TIFF"
});

// **************************************************************************************************************
// Title      : Agricultural Drought Monitoring using Google Earth Engine: 
//              A Study of Paschim Medinipur District, West Bengal
// Authors    : Pulakesh Pradhan, Sribas Patra
// Contact    : pulakesh.mid@gmail.com
// Citation   : Pradhan, P., & Patra, S. (2024). Agricultural drought monitoring using Google Earth Engine: 
//              A study of Paschim Medinipur district, West Bengal. In *Modern Cartography* (pp. 261â€“297). 
//              Elsevier. https://doi.org/10.1016/B978-0-443-23890-1.00011-6
//
// Link
print('https://doi.org/10.1016/B978-0-443-23890-1.00011-6');
// **************************************************************************************************************
// -----------------------------------------------
//// Landsat Collection with LST
var geometry = ee.FeatureCollection("users/pulakesh/PM")
Map.centerObject(geometry)

//=========================================================================L5 functions
// Function to calculate NDVI.
function calculateNDVI_L5(image) {
  var ndvi = image.normalizedDifference(['SR_B4', 'SR_B3']).rename('NDVI');
  return image.addBands(ndvi)
  .copyProperties(image, ["system:time_start"]);
}

// Function to calculate EVI for Landsat 5.
function calculateEVI_L5(image) {
  var evi = image.expression(
    '2.5 * ((NIR - RED) / (NIR + 6 * RED - 7.5 * BLUE + 1))', {
      'NIR': image.select('SR_B4'),
      'RED': image.select('SR_B3'),
      'BLUE': image.select('SR_B1')
    }).rename('EVI');

  return image.addBands(evi)
    .copyProperties(image, ["system:time_start"]);
}

// Function to calculate NDWI.
function calculateNDWI_L5(image) {
  var ndwi = image.normalizedDifference(['SR_B2', 'SR_B4']).rename('NDWI');
  return image.addBands(ndwi)
  .copyProperties(image, ["system:time_start"]);
}

// Function to calculate NDMI.
function calculateNDMI_L5(image) {
  var ndvi = image.normalizedDifference(['SR_B4', 'SR_B3']).rename('NDVI');
  var ndwi = image.normalizedDifference(['SR_B2', 'SR_B4']).rename('NDWI');
  var NDMI = image.expression(
    '(NDVI - NDWI) / (NDVI + NDWI)', {
      'NDVI': ndvi,
      'NDWI': ndwi
    }).rename('NDMI');

  return image.addBands(NDMI)
    .copyProperties(image, ["system:time_start"]);
}

// Function to calculate Land Surface Temperature (LST).
function calculateLST_L5(image) {
  var ndvi = image.normalizedDifference(['SR_B4', 'SR_B3']).rename('NDVI');
  var thermal = image.select('ST_B6').multiply(0.1);
  var minNDVI = ee.Number(ndvi.reduceRegion({ reducer: ee.Reducer.min(), scale: 30, maxPixels: 1e9 }).values().get(0));
  var maxNDVI = ee.Number(ndvi.reduceRegion({ reducer: ee.Reducer.max(), scale: 30, maxPixels: 1e9 }).values().get(0));
  var fv = ndvi.subtract(minNDVI).divide(maxNDVI.subtract(minNDVI)).pow(ee.Number(2)).rename('FV');
  var a = ee.Number(0.004);
  var b = ee.Number(0.986);
  var EM = fv.multiply(a).add(b).rename('EMM');

  var LST = thermal.expression(
    '(Tb/(1 + (0.00115 * (Tb / 1.438)) * log(Ep)))', {
      'Tb': thermal.select('ST_B6'),
      'Ep': EM.select('EMM')
    }).rename('LST');

  return image.addBands(LST)
  .copyProperties(image, ["system:time_start"]);
}

// Applies scaling factors.
function applyScaleFactors5(image) {
  var opticalBands = image.select('SR_B.').multiply(0.0000275).add(-0.2);
  var thermalBand = image.select('ST_B6').multiply(0.00341802).add(149.0);
  return image.addBands(opticalBands, null, true)
              .addBands(thermalBand, null, true);
}

function slcError(image) {
  return image.focal_mean(1, 'square', 'pixels', 8)
  .copyProperties(image, ["system:time_start"]);
}

// Load Landsat 5 image collection.
var landsat5 = ee.ImageCollection('LANDSAT/LT05/C02/T1_L2').map(applyScaleFactors5);

// Filter the collection by date and region.
var filteredLandsat5 = landsat5.filterDate('2003-10-01', '2007-12-01').filter(ee.Filter.calendarRange(10, 11, 'month')).filterBounds(geometry).filter(ee.Filter.lt('CLOUD_COVER', 5)).select(['SR_B1', 'SR_B2', 'SR_B3', 'SR_B4', 'SR_B5', 'SR_B7','ST_B6']);

filteredLandsat5 = filteredLandsat5.map(calculateNDVI_L5).map(calculateNDWI_L5).map(calculateLST_L5).map(calculateNDMI_L5);

// Function to calculate BT.
function calculateBT(image) {
  var bt = image.select('ST_B6').rename('BT'); // use the scale factor for Collection 2 data
  return image.addBands(bt);
}
filteredLandsat5 = filteredLandsat5.map(calculateBT);

// Function to calculate VCI
function calculateVCI(image) {
  var minNDVI = filteredLandsat5.min().select('NDVI');
  var maxNDVI = filteredLandsat5.max().select('NDVI');
  var vci = image.expression(
    '(NDVI - minNDVI) / (maxNDVI - minNDVI)', {
      'NDVI': image.select('NDVI'),
      'minNDVI': minNDVI,
      'maxNDVI': maxNDVI
    }).rename('VCI');
  return image.addBands(vci);
}
// Function to calculate TCI
function calculateTCI(image) {
  var minBT = filteredLandsat5.min().select('BT');
  var maxBT = filteredLandsat5.max().select('BT');
  var tci = image.expression(
    '(maxBT - BT) / (maxBT - minBT)', {
      'BT': image.select('BT'),
      'minBT': minBT,
      'maxBT': maxBT
    }).rename('TCI');
  return image.addBands(tci);
}
// Function to calculate VHI
function calculateVHI(image) {
  var vhi = image.expression(
    '0.5 * VCI + 0.5 * TCI', {
      'VCI': image.select('VCI'),
      'TCI': image.select('TCI')
    }).rename('VHI');
  return image.addBands(vhi);
}

filteredLandsat5 = filteredLandsat5.map(calculateVCI).map(calculateTCI).map(calculateVHI);

// Visualization parameters
var ndviVis = { min: 0, max: 1, palette: ['ffffff', 'ce7e45', 'df923d', 'f1b555', 'fcd163', '99b718', '74a901','66a000', '529400', '3e8601', '207401', '056201', '004c00', '023b01','012e01', '011d01', '011301'] };
var NDMIVis = { min: -1, max: 1, palette: ['#d73027','#fc8d59','#fee08b','#ffffbf','#d9ef8b','#91cf60','#1a9850'] };
var lstVis = { min: 20, max: 40, palette: [ '040274', '040281', '0502a3', '0502b8', '0502ce', '0502e6','0602ff', '235cb1', '307ef3', '269db1', '30c8e2', '32d3ef','3be285', '3ff38f', '86e26f', '3ae237', 'b5e22e', 'd6e21f','fff705', 'ffd611', 'ffb613', 'ff8b13', 'ff6e08', 'ff500d','ff0000', 'de0101', 'c21301', 'a71001', '911003'] };
var eviVis = { min: 0, max: 1, palette: ['ffffff', 'ce7e45', 'df923d', 'f1b555', 'fcd163', '99b718', '74a901','66a000', '529400', '3e8601', '207401', '056201', '004c00', '023b01','012e01', '011d01', '011301'] };

// Display NDVI, NDWI, LST, NDMI, VCI, TCI and VHI
var indices = ['NDVI', 'NDWI','LST', 'NDMI', 'VCI', 'TCI', 'VHI'];
indices.forEach(function(index) {
  var clipped = filteredLandsat5.map(function(image) {
    return image.select(index).clip(geometry);
  });
  Map.addLayer(clipped, {min: -1, max: 1, palette: ['red', 'yellow', 'green']}, index);
});

var firstImage = filteredLandsat5.first();
indices.forEach(function(index) {
  var stats = firstImage.select(index).reduceRegion({
    reducer: ee.Reducer.minMax().combine({
      reducer2: ee.Reducer.mean(),
      sharedInputs: true
    }).combine({
      reducer2: ee.Reducer.stdDev(),
      sharedInputs: true
    }),
    geometry: geometry,
    scale: 30,  // change this to your needed scale
    maxPixels: 1e9
  });
  print(index + ' Image Stats:', stats);
});

//=============================================
// Initialize an empty list to store stats
var statsList = ee.List([]);
indices.forEach(function(index) {
  var stats = firstImage.select(index).reduceRegion({
    reducer: ee.Reducer.minMax().combine({
      reducer2: ee.Reducer.mean(),
      sharedInputs: true
    }).combine({
      reducer2: ee.Reducer.stdDev(),
      sharedInputs: true
    }),
    geometry: geometry,
    scale: 30,  // change this to your needed scale
    maxPixels: 1e9
  });
  // Add the stats to the list
  statsList = statsList.add(stats);
});
// Convert the list to a feature collection
var statsFC = ee.FeatureCollection(statsList.map(function(el){
  return ee.Feature(null, el);
}));
// Export the feature collection to a CSV file in Google Drive
Export.table.toDrive({
  collection: statsFC,
  description: 'image_stats',
  fileFormat: 'CSV'
});

indices.forEach(function(index) {
  // Define the classification thresholds
  var thresholds = [0, 0.2, 0.4, 0.6, 0.8];
  // Define the colors for the classes
  var colors = ['darkblue', 'blue', 'yellow', 'lightgreen', 'green', 'darkgreen'];
  // Create a classified image using the thresholds and colors
  var classImage = firstImage.select(index)
    .lt(thresholds[0]).multiply(1)
    .add(firstImage.select(index).gte(thresholds[0]).and(firstImage.select(index).lt(thresholds[1])).multiply(2))
    .add(firstImage.select(index).gte(thresholds[1]).and(firstImage.select(index).lt(thresholds[2])).multiply(3))
    .add(firstImage.select(index).gte(thresholds[2]).and(firstImage.select(index).lt(thresholds[3])).multiply(4))
    .add(firstImage.select(index).gte(thresholds[3]).and(firstImage.select(index).lt(thresholds[4])).multiply(5))
    .add(firstImage.select(index).gte(thresholds[4]).multiply(6))
    .clip(geometry)
    .selfMask();
  // Display the classified image
  Map.addLayer(classImage, { min: 1, max: 6, palette: colors }, index + ' Classes');
  // Calculate the area of each class
  var areaImage = ee.Image.pixelArea().divide(1e6).addBands(classImage);
  var areas = areaImage.reduceRegion({
    reducer: ee.Reducer.sum().group({
      groupField: 1,
      groupName: 'class',
    }),
    geometry: geometry,
    scale: 30,  // change this to your needed scale
    maxPixels: 1e9
  });
  print(index + ' Area by class (sq km):', areas.get('groups'));
  // Assuming 'dataList' is your list
  var dataList = ee.List(areas.get('groups'));
  // Extract the class and sum values
  var classes = dataList.map(function(item) {
    return ee.Number(ee.Dictionary(item).get('class'));
  });
  var sums = dataList.map(function(item) {
    return ee.Number(ee.Dictionary(item).get('sum'));
  });
  // Create the chart
  var histogram = ui.Chart.array.values(sums, 0, classes)
    .setChartType('ColumnChart')
    .setOptions({
      title: index + ' Histogram',
      hAxis: {title: 'Classes'},
      vAxis: {title: 'Sum'},
      series: {
        0: { color: '#0000FF' },
        1: { color: '#008000' },
        2: { color: '#808080' },
        3: { color: '#F0E68C' },
        4: { color: '#FFFF00' },
        5: { color: '#A0522D' }
      }
    });
  print(histogram);
});

indices.forEach(function(index) {
  var chart = ui.Chart.image.series({
    imageCollection: filteredLandsat5.select([index]),
    region: geometry,
    reducer: ee.Reducer.mean(),
    scale: 30
  }).setChartType('LineChart')
    .setOptions({
      lineWidth: 1,
      pointSize: 2,
      title: index + ' Time-Series',
      vAxis: {title: index},
      hAxis: {title: '', format: 'YYYY-MMM', gridlines: {count: 12}},
      series: {
        0: {color: 'red'},
        1: {color: 'blue'}
      },
    });
  print(chart);
});

indices.forEach(function(index) {
  // Function to calculate class-wise areas for each feature
  function calculateClassWiseAreas(feature) {
    var thresholds = [0, 0.2, 0.4, 0.6, 0.8];
    var classImage = firstImage.select(index)
      .lt(thresholds[0]).multiply(1)
      .add(firstImage.select(index).gte(thresholds[0]).and(firstImage.select(index).lt(thresholds[1])).multiply(2))
      .add(firstImage.select(index).gte(thresholds[1]).and(firstImage.select(index).lt(thresholds[2])).multiply(3))
