function getGammaDistParams(col){ 
  var col_no0 = col.map(function(img){return img.updateMask(img.neq(0))});
  var N=col_no0.count();
  var sum_log=col_no0.map(function(img){return img.log()}).sum();
  var A = (col_no0.mean().log()).subtract(sum_log.divide(N));
  var iA4 = ee.Image.constant(4).multiply(A);
  var i1 = ee.Image.constant(1);
  var i3 = ee.Image.constant(3);
  var alpha = (i1.divide(iA4)).multiply(i1.add((i1.add(iA4.divide(i3))).sqrt()));
  var beta = col_no0.mean().divide(alpha);
  var param = alpha.addBands(beta).select([0,1],["alpha","beta"]);
  return param;
}
function getQ(col){
  var PiNot0 = col.map(function(img){return img.updateMask(img.neq(0))});
  var N = col.count();
  var m = N.subtract(PiNot0.count());
  var q = ee.Image(m.divide(N));
  return q.select([0], ['q']); 
}
