/*
Alice Alonso and Manon Creplet, April 2021 
Computation of the SPEI according to 
Vicente-Serrano, S. M., Beguería, S. & López-Moreno, J. I. 
A multiscalar drought index sensitive to global warming: The standardized precipitation evapotranspiration index. J. Clim. 23, 1696–1718 (2010).
Note: Assumption that the data  follow a log-logistic distribution. This should be verified.
*/
var pointLocation = ee.FeatureCollection("users/pulakesh/PM");
//____________________________________________________________________________
// FUNCTIONS DEFINITION
var clipROI = function (image){ return image.clip(Burundi); };
function getLoglogisticDistParam(col){
  var N = col.count();
  var array = col.toArray();
  var DiSorted = array.arraySlice(1, 0).arraySort().arrayProject([0]);
  var i = ee.Image.constant(ee.Array(ee.List.sequence(1, col.size())));
  var Fi = ((i.subtract(ee.Image.constant(.35))).divide(N));
  var FiDi = DiSorted.addBands(Fi).select([0,1], ['DiSorted', 'Fi']);
  var pwm0 = ee.Image(((ee.Image.constant(1).subtract(Fi)).pow(0).multiply(DiSorted)))
      .arrayAccum(0).arraySlice(0, N.subtract(1)).divide(N);
  var pwm1 = ee.Image(((ee.Image.constant(1).subtract(Fi)).pow(1).multiply(DiSorted)))
      .arrayAccum(0).arraySlice(0, N.subtract(1)).divide(N);
  var pwm2 = ee.Image(((ee.Image.constant(1).subtract(Fi)).pow(2).multiply(DiSorted)))
      .arrayAccum(0).arraySlice(0, N.subtract(1)).divide(N);
  var pwm = pwm0.addBands(pwm1).addBands(pwm2);
  var i1 = ee.Image.constant(1);
  var i2 = ee.Image.constant(2);
  var i6 = ee.Image.constant(6);
  var beta = (i2.multiply(pwm1).subtract(pwm0)).divide((i6.multiply(pwm1)).subtract(pwm0).subtract(i6.multiply(pwm2)));
  var gamF1 = (i1.add(i1.divide(beta))).gamma();
  var gamF2 = (i1.subtract(i1.divide(beta))).gamma();
  var alpha = ((pwm0.subtract(i2.multiply(pwm1))).multiply(beta)).divide((gamF1).multiply(gamF2));
  var gamm = pwm0.subtract((alpha).multiply(gamF1).multiply(gamF2));
  var param = beta.addBands(alpha).addBands(gamm).select([0,1,2],['beta','alpha','gamma']);  
  return param;
}
function getFxSPEI(img){
  var i1 = ee.Image.constant(1);
  var in1 = ee.Image.constant(-1);
  var in2 = ee.Image.constant(-2);
  var Fx = (i1.add((alpha.divide(img.subtract(gamm))).pow(beta))).pow(-1).arrayFlatten([['0']]);
  var Px = i1.subtract(Fx);
  var W1 = (in2.multiply((Px).log())).sqrt();
  var W2 = (in2.multiply((i1.subtract(Px)).log())).sqrt();
  var W = W1.where(Px.gt(ee.Image.constant(.5)), W2);
  var C0 = ee.Image.constant(2.515517);
  var C1 = ee.Image.constant(0.802853);
  var C2 = ee.Image.constant(0.010328);
  var d1 = ee.Image.constant(1.432788);
  var d2 = ee.Image.constant(0.189269);
  var d3 = ee.Image.constant(0.001308);
  var SPEI00 = W.subtract((C0.add(C1.multiply(W)).add(C2.multiply(W.pow(2)))).divide(i1.add(d1.multiply(W)).add(d2.multiply(W.pow(2))).add(d3.multiply(W.pow(3)))));
  var SPEI0 = SPEI00.where(Px.gt(ee.Image.constant(.5)), in1.multiply(SPEI00));
  var SPEI = Fx.addBands(SPEI0).select([0,1], ['Fx', 'SPEI']).set({'time': ee.Date.fromYMD(img.get('year'), img.get('month'), 1)});
  return SPEI;
}
