var geometry = ee.FeatureCollection('users/pulakesh/PM');

// ==============================
// ⚙️ SCALING FUNCTION FOR VARIABLES
// ==============================
function applyScale(image) {
  return image
    .addBands(image.select('aet').multiply(0.1), null, true)
    .addBands(image.select('def').multiply(0.1), null, true)
    .addBands(image.select('pdsi').multiply(0.01), null, true)
    .addBands(image.select('pet').multiply(0.1), null, true)
    .addBands(image.select('soil').multiply(0.1), null, true)
    .addBands(image.select('srad').multiply(0.1), null, true)
    .addBands(image.select('tmmn').multiply(0.1), null, true)
    .addBands(image.select('tmmx').multiply(0.1), null, true)
    .addBands(image.select('vap').multiply(0.001), null, true)
    .addBands(image.select('vpd').multiply(0.01), null, true)
    .addBands(image.select('vs').multiply(0.01), null, true);
}

// ==============================
// 🌍 LOAD AND SCALE TERRACLIMATE DATASET
// ==============================
var dataset = ee.ImageCollection('IDAHO_EPSCOR/TERRACLIMATE')
                .map(applyScale);

// ==============================
// 📈 TIME SERIES CHARTS FOR VARIABLES
// ==============================
var indices = ['aet', 'def', 'pdsi', 'pet', 'pr', 'ro', 'swe', 'soil', 'srad', 
               'tmmn', 'tmmx', 'vap', 'vpd', 'vs'];

indices.forEach(function(index) {
  var chart = ui.Chart.image.series({
      imageCollection: dataset.select([index]),
      region: geometry,
      reducer: ee.Reducer.mean(),
      scale: 4638.3
    })
    .setChartType('LineChart')
    .setOptions({
      title: 'Monthly ' + index.toUpperCase() + ' Time-Series (2002–2022)',
      hAxis: { title: '', format: 'YYYY-MMM', gridlines: { count: 12 }},
      vAxis: { title: index },
      lineWidth: 1,
      pointSize: 0,
      series: {
        0: { color: 'red' }
      }
    });
  print(chart);
});

